import{_ as s,c as n,o as l,ae as i}from"./chunks/framework.DTLW3OlO.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"document/Linux.md","filePath":"document/Linux.md"}'),t={name:"document/Linux.md"};function p(e,a,o,c,u,d){return l(),n("div",null,a[0]||(a[0]=[i(`<h2 id="linux-学习笔记" tabindex="-1">Linux 学习笔记 <a class="header-anchor" href="#linux-学习笔记" aria-label="Permalink to &quot;Linux 学习笔记&quot;">​</a></h2><ul><li>校验nginx配置是否正确： nginx -t <ul><li>修改完:vim /usr/local/nginx/conf/vhost/console.browser.qihoo.net.conf 这个文件后，校验一下</li></ul></li><li>重启nginx：nginx -s reload <ul><li>中间可能会遇到权限不够的问题，输入指令：sudo -s 并输入服务器密码，之后可以</li></ul></li><li>删除文件： rm -rf /xxx 删除服务器根路径下的xxx下所有文件</li><li>修改文件权限： chmod -R 777 browser-corp-qihoo-net/</li><li>修改文件属组： chown -R 属主名:属组名 文件名</li><li>切换到sudo权限： sudo -s 或 sudo -i</li><li>退出sudo权限： exit 或 logout 或 ctrl + D</li><li>查看当前所处目录：pwd</li><li>访问远程资源：curl<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  curl http://www.baidu.com</span></span>
<span class="line"><span>  // -o 将结果写入到文件</span></span>
<span class="line"><span>  curl http://baidu.com -o baidu.html</span></span>
<span class="line"><span>  // -X 指定请求方式</span></span>
<span class="line"><span>  curl -XPOST http://www.baidu.com</span></span>
<span class="line"><span>  // -H 指定请求头</span></span>
<span class="line"><span>  curl -H &#39;token:xxx&#39; -H &#39;a:yyy&#39; http://www.baidu.com</span></span>
<span class="line"><span>  // -b 携带cookie</span></span>
<span class="line"><span>  curl -b &#39;a=123&#39; http://www.baidu.com</span></span>
<span class="line"><span>  // -c 将返回的cookie写入本地文件</span></span>
<span class="line"><span>  curl -c xxx.txt http://www.baidu.com</span></span>
<span class="line"><span>  // -d 请求内容</span></span>
<span class="line"><span>  curl -d &#39;a=123&amp;b=456&#39; -XPOST http://baidu.com</span></span>
<span class="line"><span>  // -e 指定referer</span></span>
<span class="line"><span>  // -k 跳过SSL检查，不检查服务端的SSL证书是否有效</span></span>
<span class="line"><span>  // -u 认证</span></span></code></pre></div></li><li>下载远程文件到本地： wget<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  // -q 安静模式 不会在终端显示下载进度</span></span>
<span class="line"><span>  // -O 输出到指定文件 -o 表示输出到终端 不指定-o下载后文件名和远程文件名一致</span></span>
<span class="line"><span>  // --header 指定请求头</span></span>
<span class="line"><span>  wget http://hanhuankang.com -O hanhuankang.html</span></span></code></pre></div></li><li>压缩和解压文件：tar<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  // -c是压缩 -x是解压 -z是zip</span></span>
<span class="line"><span>  // -czvf 压缩文件</span></span>
<span class="line"><span>  tar -czvf xxx.tar.gz dir1 dir2 file1 file2</span></span>
<span class="line"><span>  // -xzvf 解压文件</span></span>
<span class="line"><span>  tar -xzvf xxx.tar.gz -C xxx</span></span></code></pre></div></li></ul><ul><li>cat 查看文件内容</li><li>netstat 查看网络情况，常用来查找指定端口，或判断端口是否在监听<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  // 查看8080端口</span></span>
<span class="line"><span>  netstat -anp | grep 8080</span></span></code></pre></div></li><li>mkdir 创建目录<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  mkdir a</span></span>
<span class="line"><span>  mkdir -p a/b/c 递归创建层级目录，即使上级目录不存在，也不会报错，而是先创建上级目录</span></span></code></pre></div></li><li>rm 删除文件和目录<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  rm a.txt</span></span>
<span class="line"><span>  rm dir1</span></span>
<span class="line"><span>  rm -rf dir2</span></span>
<span class="line"><span>  // 添加 -rf 时 需要非常仔细查看命令是都正确，有时候因为一个不起眼的空格可能就变成 rm -rf / dir2 或者要删除的目录时变量，但是很不幸变量没有正确赋值，这时候 rm -rf 的破坏力是很大的</span></span></code></pre></div></li><li>mv 移动文件或目录<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  // 移动文件或目录，常用来修改文件或目录名</span></span>
<span class="line"><span>  mv a.txt b.txt</span></span>
<span class="line"><span>  ma dir1 dir2</span></span></code></pre></div></li><li>cp 复制文件或目录<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  cp a.txt b.txt</span></span>
<span class="line"><span>  // 复制目录时需要添加 -r，表示递归的意思</span></span>
<span class="line"><span>  cp -r dir1 dir2</span></span></code></pre></div></li><li>cd 切换目录</li><li>ll 列出当前目录或指定目录下的文件和目录，有些环境（如docker容器）没有这个命令，用 ls -l 代替</li><li>man 查看命令帮助文档<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  //查看ls的帮助文档</span></span>
<span class="line"><span>  man ls</span></span>
<span class="line"><span>  // 查看文档第一页</span></span>
<span class="line"><span>  man 1 ls</span></span></code></pre></div></li><li>使用 CMD 命令 启动 c盘下的nginx<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  // 进入c盘下的文件目录</span></span>
<span class="line"><span>  c:&amp;&amp; cd c:\\tools\\nginx</span></span>
<span class="line"><span>  start nginx</span></span></code></pre></div></li><li>wget 命令行下载文件 <ul><li>下载该网站上 packs 目录中的所有文件: wget -r -np -nd <a href="http://www.linux.com/packs/" target="_blank" rel="noreferrer">http://www.linux.com/packs/</a><ul><li>-np 的作用是不便利父目录，-nd表示不再本机重新创建目录结构</li></ul></li><li>下载整个 http 或 ftp 站点: wget -r -x <a href="http://www.linux.com" target="_blank" rel="noreferrer">http://www.linux.com</a><ul><li>-x 的作用强制建立服务器上一模一样的目录（这个命令会按照递归深度将网站上所有引用的其它网站全都下载下来</li><li>可以用 -l number 参数来指定下载的层次，如只下载两层，那么使用 -l 2：wget -r -x -l 2 <a href="http://www.linux.com" target="_blank" rel="noreferrer">http://www.linux.com</a>）</li></ul></li><li>选择性只下载某类文件：wget -r -np -nd -accept=iso http:www.linux.com/i386/ <ul><li>表示仅下载i386目录中扩展名为iso的文件，可以指定多个扩展名，以逗号分隔</li></ul></li><li>批量下载：wget -i downloads.txt <ul><li>如果需要下载多个文件，那么把需要下载的文件的地址放到 downloads.txt 中，每个文件的URL写一行，然后wget就会自动为你下载所有文件了</li></ul></li><li>断点续传：wget -c -t 100 -T 120 <a href="http://www.linux.com/big-file.iso" target="_blank" rel="noreferrer">http://www.linux.com/big-file.iso</a><ul><li>当文件特别大或者网络慢时，往往一个文件还没有下载完，连接就已经被切断，此时就需要断点续传，wget的断点续传是自动的。</li><li>-c 选项的作用为断点续传</li><li>-t 参数表示重试次数，如：-t 100 表示重试100次</li><li>-T参数表示超时等待时间，例如 -T 120，表示等待 120秒 连接不上就算超时</li></ul></li><li>镜像一个网站：wget -m -k (-H) <a href="http://www.linux.com/" target="_blank" rel="noreferrer">http://www.linux.com/</a><ul><li>如果网站中的图像是放在另外的站点，那么可以使用-H选项</li></ul></li></ul></li><li>df、du Linux系统下查看磁盘与目录的容量 <ul><li>df：列出文件系统整体磁盘使用量</li><li>du：评估文件系统的磁盘使用量（常用语评估目录所占容量）</li><li>df 参数<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  -a: 列出所有的文件系统</span></span>
<span class="line"><span>  -k: 以KB容量显示各文件系统</span></span>
<span class="line"><span>  -m: 以MB容量显示各文件系统</span></span>
<span class="line"><span>  -h: 以人们较易阅读的GB,MB,KB等格式自行显示</span></span>
<span class="line"><span>  -H: 以M=1000K代替M-1024K的进位方式</span></span>
<span class="line"><span>  -T: 连同该分区的文件系统名称(例如 ext3)也列出</span></span>
<span class="line"><span>  -i: 不同硬盘容量，而以inode的数量来显示</span></span></code></pre></div></li><li>du 参数<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  -a: 列出所有的文件与目录容量，因为默认仅统计目录下面的文件量而已</span></span>
<span class="line"><span>  -h: 以人们较易读的容量格式(G/M)显示</span></span>
<span class="line"><span>  -s: 列出总量，而不列出每个个别的目录占用的容量</span></span>
<span class="line"><span>  -S: 不包括子目录下的总计，与-s有点差别</span></span>
<span class="line"><span>  -k: 以KB列出容量显示</span></span>
<span class="line"><span>  -m: 以MB列出容量显示</span></span></code></pre></div></li></ul></li><li>wc 统计指定文件中的字节数、字数、行数，并将统计结果显示输出 <ul><li>wc --help 可以查看具体命令</li><li>wc -l filename 就是查看文件里有多少行</li><li>wc -w filename 查看文件里有多少个word</li><li>wc -L filename 文件里最长的那一行是多少个字</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  -c: 统计字节数</span></span>
<span class="line"><span>  -l: 统计行数</span></span>
<span class="line"><span>  -w: 统计字数</span></span>
<span class="line"><span>  wc -lcw file1 file2  // 输出两个文件的字节数、行数、字数</span></span>
<span class="line"><span>  // 使用 ls -lht 命令显示当前目录下的所有文件 其中有一列就时是显示这个文件的大小</span></span></code></pre></div></li><li>uniq 求两个Linux文本文件的交集、并集、差集 <ul><li>交集 sort a.txt b.txt | uniq -d</li><li>并集 sort a.txt b.txt | uniq</li><li>差集 sort a.txt b.txt b.txt | uniq -u // a.txt 对 b.txt 的差集</li><li>使用 sort 可以将文件进行排序(sort排序后是为了通过管道交给 uniq 处理，uniq只能处理相邻的行)， <ul><li>使用sort后面的参数，例如 -n 按照数字格式排序，-i忽略大小写，例如 -r逆序输出等</li></ul></li><li>uniq 为删除文件中重复的行，得到文件中唯一的行 <ul><li>参数 -d 表示的是输出出现次数大于1的内容；参数 -u 表示的是输出出现次数为1的内容</li></ul></li><li>比较两个文件的交并补，并输出为一个新文件 <ul><li>并集 cat file1.txt file2.txt | sort | uniq &gt; file.txt</li><li>交集 cat file1.txt file2.txt | sort | uniq -d &gt; file.txt</li><li>差集 cat file1.txt file2.txt file2.txt | sort | uniq -u &gt; file.txt</li></ul></li></ul></li><li>grep <ul><li>grep -n &#39;word&#39; &#39;file&#39; -- 返回 &#39;file&#39; 文件中包含 &#39;word&#39; 的所有行</li></ul></li><li>sed <ul><li>shell 中最核心的三个命令: grep、sed、awk</li><li>sed -n &#39;2,$p&#39; a &gt; b -- 把 a 文件的第 2 行到 最后一行，输出到 b 文件,$p代表文件末尾，即最后一行</li></ul></li><li>cat <ul><li>cat 查看文件</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  cat test.log | head -n 200  //查看test.log的前200行</span></span>
<span class="line"><span>  cat test.log | tail -n 200  //查看test.log倒数200行</span></span>
<span class="line"><span>  cat test.log | grep &#39;http&#39;  //返回test.log中包含http的所有行</span></span>
<span class="line"><span>  cat /etc/passwd | grep -A5 root // 查找文件passwd中包含root的 后5行</span></span>
<span class="line"><span>  cat /etc/passwd | grep -B5 root // 查找文件passwd中包含root的 前5行</span></span></code></pre></div></li><li>echo 输出内容，可以输出内容到文件等 <ul><li>echo &#39;add content&#39;&gt;&gt;/home/data/test.sh 向文件末尾追加数据</li><li>echo &#39;add content&#39;&gt;/home/data/test.sh 删除原有内容，并写入当前内容</li></ul></li><li>tar 压缩、解压文件 <ul><li>打包成 tar.gz 格式的压缩包: tar -zcvf demo.tar.gz demo/</li><li>解压 tar.gz 格式的压缩包： tar zxvf demo.tar.gz</li><li>打包成 tar.bz2 格式压缩包：tar -jcvf demo.tar.bz2 demo/</li><li>解压 tar.bz2 格式压缩包： tar jxvf demo.tar.bz2</li><li>打包成 zip 格式的压缩包：zip -q -r demo.zip demo/</li><li>解压 zip 格式的压缩包： unzip demo.zip</li></ul></li><li>netstat 查询端口号对应的进程号 <ul><li>netstat -tnpl | grep :80</li></ul></li><li>ls -l /proc/9970 查看指定进程号的进程信息</li><li>awk <ul><li>获取文件 20210925_v2 中，包含 &quot;id&quot;: &quot;360kan 的行数: cat 20210925_v2 | grep &#39;&quot;id&quot;: &quot;360kan&#39; | awk -F &#39;&quot;id&quot;: &quot;&#39; &#39;{print $2}&#39; | awk -F &#39;&quot;&#39; &#39;{print $1}&#39; | wc -l</li></ul></li><li>grep -v <ul><li>获取文件 20210926_v2 中，包含 &quot;&quot;id&quot;:\\s&quot;360kan_&quot;，但不包含 &quot;&quot;unique_id&quot;:\\s&quot;360kan_&quot; 的行数： grep &quot;&quot;id&quot;:\\s&quot;360kan_&quot; 20210926_v2 | grep -v &quot;&quot;unique_id&quot;:\\s&quot;360kan_&quot; | wc -l</li><li>将文件 20210926_v2 中，包含 &quot;&quot;id&quot;:\\s&quot;360kan_&quot;，但不包含 &quot;&quot;unique_id&quot;:\\s&quot;360kan_&quot; 的行，输出到新文件 中： grep &quot;&quot;id&quot;:\\s&quot;360kan_&quot; 20210926_v2 | grep -v &quot;&quot;unique_id&quot;:\\s&quot;360kan_&quot; &gt; ~/haha.01.txt</li><li>将文件 20210926_v2 中，包含 &quot;&quot;id&quot;:\\s&quot;360kan_&quot;，但不包含 &quot;&quot;unique_id&quot;:\\s&quot;360kan_&quot;, 且不含 &quot;&quot;category&quot;:\\s&quot;Null&quot;&quot; 的行，输出到新文件 中： grep &quot;&quot;id&quot;:\\s&quot;360kan_&quot; 20210926_v2 | grep -v &quot;&quot;unique_id&quot;:\\s&quot;360kan_&quot; | grep -v &quot;&quot;category&quot;:\\s&quot;Null&quot;&quot; &gt; ~/haha.02.txt</li></ul></li><li>查看文件的大小： du -sh ~/haha.01.txt // 52MB</li><li>定时任务 crontab <ul><li>查看定时任务： crontab -l</li><li>编辑定时任务： crontab -e</li></ul></li></ul>`,3)]))}const g=s(t,[["render",p]]);export{h as __pageData,g as default};
